/**
 * Bundled default Blue Alliance partner logo — auto-generated from
 * `bluealliance.png` (repo root) via a one-off sharp downscale
 * (original 1500x600 -> 400x160, PNG re-encoded).
 *
 * WHY bundled as a source constant instead of read from `public/` at
 * runtime: the Next.js standalone server output does not reliably carry
 * arbitrary `public/` files into the Docker runtime image filesystem
 * layout used by this app's server build, and this asset must be available
 * with zero I/O and zero S3/MinIO dependency (it is the fallback used when
 * S3 is exactly what is NOT configured/available for a template). A plain
 * TS/JS module import is guaranteed to survive whatever bundling target
 * (standalone server, Docker, serverless) the app is built with.
 *
 * Regenerate with:
 *   node -e "const sharp=require('sharp'); ..." (see get-report-map-report-data.ts
 *   git history / DECISIONS_LOG for the exact one-off command used).
 *
 * DO NOT hand-edit the base64 payload below.
 */

export const BLUE_ALLIANCE_DEFAULT_LOGO_DATA_URI =
  'data:image/png;base64,';
